// Junta los empleos de todas las búsquedas, deduplica y arma el email
const all = [];
for (const item of $input.all()) {
  const jobs = (item.json && item.json.jobs) || [];
  for (const j of jobs) all.push(j);
}
// Deduplicar por URL
const seen = new Set();
const uniq = [];
for (const j of all) {
  if (j.url && !seen.has(j.url)) { seen.add(j.url); uniq.push(j); }
}
// Palabras clave que suman fit (partnerships, ventas, automatización, datos)
const KW = ['automation','automat','ai ','partnership','sales','account','growth','data','analyst','no-code','nocode','workflow'];
uniq.forEach(j => {
  const t = (j.title || '').toLowerCase();
  j._score = KW.reduce((s,k)=> s + (t.includes(k) ? 1 : 0), 0);
});
uniq.sort((a,b) => (b._score - a._score) || (new Date(b.publication_date) - new Date(a.publication_date)));
const top = uniq.slice(0, 10);

let html = '<h2>🎯 Cazador de Empleos — roles remotos para vos</h2>';
html += '<p>Encontré ' + top.length + ' roles que encajan con tu perfil (IA Automation / Data / Partnerships):</p><ul>';
for (const j of top) {
  const loc = j.candidate_required_location || 'Remoto';
  const sal = j.salary ? (' · ' + j.salary) : '';
  html += `<li style="margin-bottom:8px"><a href="${j.url}"><b>${j.title}</b></a> — ${j.company_name} (${loc})${sal}</li>`;
}
html += '</ul><p style="color:#888;font-size:12px">Automatizado con n8n · Lleyton IA Automation</p>';

return [{ json: { html, count: top.length } }];
